        wallet,
        uuid: randomUUID(),
        email: wallet,
        // unique stats key
        unsettledBytes: "0",
        servedBytesLifetime: "0",
        balanceBaseUnits: "0",
        quotaBytes: "0",
        active: false,
        createdAt: Date.now()
